from typing import Set, List, Optional, Iterable

from geosat.cloud import PointCloud, pyvoxels
from geosat.psanp.abstractions.classifier import Classifier
from geosat.psanp.abstractions.option import Option
from geosat.psanp.abstractions.pipelinemetadata import PipelineMetadata


class SubsampleClassifier(Classifier):
    """A classifier that arbitrarily picks a single point in each voxel,
    and unclassifies the rest of the points.
    """

    def __init__(
        self,
        gsd=0.25,
        stage_name: Optional[str] = None,
        output_class: str = "unclassified",
    ):
        super().__init__(stage_name)
        self.gsd = gsd
        self.output_class = output_class

    @classmethod
    def options(cls) -> List[Option]:
        return [
            Option("gsd", "size of voxel used", type_cast=float, required=False),
            Option(
                "output_class",
                description="The class to use for the points that have been filtered out",
                type_cast=str,
                required=False,
            ),
        ]

    def execute_on(
        self, cloud: PointCloud, pipeline_metadata: PipelineMetadata
    ) -> Iterable[PointCloud]:
        if len(cloud) == 0:
            return (cloud,)
        class_code = pipeline_metadata.classification_codes[self.output_class]
        representatives = list(pyvoxels.find_representatives(cloud, self.gsd).values())
        representative_classes = cloud.classification[representatives]
        cloud.classification[:] = class_code
        cloud.classification[representatives] = representative_classes
        return (cloud,)

    def input_classes(self) -> Set[str]:
        return set()

    def output_classes(self) -> Set[str]:
        return {self.output_class}
